-          !(VectorizableTree.front()->isGather() &&
-            !IE->UserTreeIndices.empty() &&
-            (ValueToGatherNodes.lookup(I).contains(
-                 VectorizableTree.front().get()) ||
-             any_of(IE->UserTreeIndices,
-                    [&](const EdgeInfo &EI) {
