-
-    if (count_if(VL, [&SourceVectors](Value *V) {
-          return !SourceVectors.contains(V);
-        }) >= 2) {
-      // Found 2nd source vector - cancel.
-      LLVM_DEBUG(dbgs() << "SLP: Gather of insertelement vectors with "
-                           "different source vectors.\n");
