-bool BoUpSLP::isFullyVectorizableTinyTree(bool ForReduction) const {
-  LLVM_DEBUG(dbgs() << "SLP: Check whether the tree with height "
-                    << VectorizableTree.size() << " is fully vectorizable .\n");
