-        SmallVector<T *> VL;
-        for (auto *It = Candidates.begin(), *End = Candidates.end(); It != End;
-             VL.clear()) {
-          auto *I = dyn_cast<Instruction>(*It);
-          if (!I || R.isDeleted(I)) {
-            ++It;
-            continue;
-          }
-          auto *SameTypeIt = It;
-          while (SameTypeIt != End &&
-                 (!isa<Instruction>(*SameTypeIt) ||
-                  R.isDeleted(cast<Instruction>(*SameTypeIt)) ||
-                  AreCompatible(*SameTypeIt, *It))) {
