-        std::optional<unsigned> EI = getExtractIndex(cast<Instruction>(V));
-        Idx = std::distance(ReorderMask.begin(), find(ReorderMask, *EI));
-      }
-    }
-    // Build the order of the VF size, need to reorder reuses shuffles, they are
-    // always of VF size.
