-              return EI.UserTE->State == TreeEntry::Vectorize &&
-                     EI.UserTE->isAltShuffle() && EI.UserTE->Idx != 0;
-            }))
-          return;
-        UserTE = UserTE->UserTreeIndices.back().UserTE;
