-      }
-      VFToOrderedEntries[TE->getVectorFactor()].insert(TE.get());
-      if (!(TE->State == TreeEntry::Vectorize ||
-            TE->State == TreeEntry::StridedVectorize) ||
-          !TE->ReuseShuffleIndices.empty())
