-bool BoUpSLP::areAllUsersVectorized(
-    Instruction *I, const SmallDenseSet<Value *> *VectorizedVals) const {
-  return (I->hasOneUse() && (!VectorizedVals || VectorizedVals->contains(I))) ||
-         all_of(I->users(), [this](User *U) {
