-                                          /*Extract=*/false, CostKind);
-  }
-  int Sz = TE.Scalars.size();
-  SmallVector<int> ReorderMask(TE.ReorderIndices.begin(),
-                               TE.ReorderIndices.end());
-  for (unsigned I : seq<unsigned>(Sz)) {
-    Value *V = TE.getOrdered(I);
-    if (isa<PoisonValue>(V)) {
