-        VL.slice(Part * SliceSize, getNumElems(VL.size(), SliceSize, Part));
-    SmallVectorImpl<const TreeEntry *> &SubEntries = Entries.emplace_back();
-    std::optional<TTI::ShuffleKind> SubRes =
