-/// and properly mark indices in mask as undef.
-/// For example, given the code
-/// \code
-/// %s1 = shufflevector <2 x ty> %0, poison, <1, 0>
-/// %s2 = shufflevector <2 x ty> %1, poison, <1, 0>
-/// \endcode
