-    case RecurKind::And:
-    case RecurKind::Or:
-    case RecurKind::SMax:
-    case RecurKind::SMin:
-    case RecurKind::UMax:
-    case RecurKind::UMin:
-    case RecurKind::FMax:
-    case RecurKind::FMin:
-    case RecurKind::FMaximum:
-    case RecurKind::FMinimum:
