-      return VectorizedValue;
-    case RecurKind::Mul:
-    case RecurKind::FMul:
-    case RecurKind::FMulAdd:
-    case RecurKind::IAnyOf:
-    case RecurKind::FAnyOf:
-    case RecurKind::IFindLastIV:
-    case RecurKind::FFindLastIV:
