-      return true;
-    if (V1->getType()->getTypeID() > V2->getType()->getTypeID())
-      return false;
-    if (V1->getType()->getScalarSizeInBits() <
-        V2->getType()->getScalarSizeInBits())
-      return true;
-    if (V1->getType()->getScalarSizeInBits() >
-        V2->getType()->getScalarSizeInBits())
