-  for (BasicBlock::iterator It = BB->begin(), E = BB->end(); It != E; ++It) {
-    // Skip instructions with scalable type. The num of elements is unknown at
-    // compile-time for scalable type.
-    if (isa<ScalableVectorType>(It->getType()))
-      continue;
