-    SmallVector<Instruction *> UserBVHead(TE.Scalars.size());
-    for (auto [I, V] : zip(UserBVHead, TE.Scalars)) {
-      if (!V->hasNUsesOrMore(1))
-        continue;
-      auto *II = dyn_cast<InsertElementInst>(*V->user_begin());
-      if (!II)
-        continue;
