-          auto It = GathersToOrders.find(OpTE);
-          if (It != GathersToOrders.end())
-            return It->second;
-        }
-        if (OpTE->isAltShuffle()) {
-          auto It = AltShufflesToOrders.find(OpTE);
-          if (It != AltShufflesToOrders.end())
-            return It->second;
