-  SmallDenseMap<Value *, SmallVector<unsigned>, 8> KeyToIndex;
-  bool IsOrdered = true;
-  unsigned NumInstructions = 0;
-  // Try to "cluster" scalar instructions, to be able to build extra vectorized
-  // nodes.
