-  /// Adds another one input vector and the mask for the shuffling.
-  void add(Value *V1, ArrayRef<int> Mask, bool ForExtracts = false) {
-    if (InVectors.empty()) {
-      assert(CommonMask.empty() && !ForExtracts &&
-             "Expected empty input mask/vectors.");
