-bool SLPVectorizerPass::tryToVectorizeList(ArrayRef<Value *> VL, BoUpSLP &R,
-                                           bool MaxVFOnly) {
-  if (VL.size() < 2)
-    return false;
-
-  LLVM_DEBUG(dbgs() << "SLP: Trying to vectorize a list of length = "
-                    << VL.size() << ".\n");
-
-  // Check that all of the parts are instructions of the same type,
-  // we permit an alternate opcode via InstructionsState.
-  InstructionsState S = getSameOpcode(VL, *TLI);
-  if (!S)
-    return false;
-
-  Instruction *I0 = S.getMainOp();
-  // Make sure invalid types (including vector type) are rejected before
-  // determining vectorization factor for scalar instructions.
-  for (Value *V : VL) {
-    Type *Ty = V->getType();
-    if (!isa<InsertElementInst>(V) && !isValidElementType(Ty)) {
-      // NOTE: the following will give user internal llvm type name, which may
-      // not be useful.
-      R.getORE()->emit([&]() {
-        std::string TypeStr;
-        llvm::raw_string_ostream rso(TypeStr);
-        Ty->print(rso);
-        return OptimizationRemarkMissed(SV_NAME, "UnsupportedType", I0)
-               << "Cannot SLP vectorize list: type "
-               << TypeStr + " is unsupported by vectorizer";
-      });
-      return false;
-    }
-  }
-
-  unsigned Sz = R.getVectorElementSize(I0);
-  unsigned MinVF = R.getMinVF(Sz);
-  unsigned MaxVF = std::max<unsigned>(llvm::bit_floor(VL.size()), MinVF);
-  MaxVF = std::min(R.getMaximumVF(Sz, S.getOpcode()), MaxVF);
-  if (MaxVF < 2) {
-    R.getORE()->emit([&]() {
-      return OptimizationRemarkMissed(SV_NAME, "SmallVF", I0)
-             << "Cannot SLP vectorize list: vectorization factor "
-             << "less than 2 is not supported";
-    });
-    return false;
-  }
-
-  bool Changed = false;
-  bool CandidateFound = false;
-  InstructionCost MinCost = SLPCostThreshold.getValue();
-  Type *ScalarTy = getValueType(VL[0]);
-
-  unsigned NextInst = 0, MaxInst = VL.size();
-  for (unsigned VF = MaxVF; NextInst + 1 < MaxInst && VF >= MinVF; VF /= 2) {
-    // No actual vectorization should happen, if number of parts is the same as
-    // provided vectorization factor (i.e. the scalar type is used for vector
-    // code during codegen).
-    auto *VecTy = getWidenedType(ScalarTy, VF);
-    if (TTI->getNumberOfParts(VecTy) == VF)
-      continue;
-    for (unsigned I = NextInst; I < MaxInst; ++I) {
-      unsigned ActualVF = std::min(MaxInst - I, VF);
-
-      if (!hasFullVectorsOrPowerOf2(*TTI, ScalarTy, ActualVF))
-        continue;
-
-      if (MaxVFOnly && ActualVF < MaxVF)
-        break;
-      if ((VF > MinVF && ActualVF <= VF / 2) || (VF == MinVF && ActualVF < 2))
-        break;
-
-      SmallVector<Value *> Ops(ActualVF, nullptr);
-      unsigned Idx = 0;
-      for (Value *V : VL.drop_front(I)) {
-        // Check that a previous iteration of this loop did not delete the
-        // Value.
-        if (auto *Inst = dyn_cast<Instruction>(V);
-            !Inst || !R.isDeleted(Inst)) {
-          Ops[Idx] = V;
-          ++Idx;
-          if (Idx == ActualVF)
-            break;
-        }
-      }
-      // Not enough vectorizable instructions - exit.
-      if (Idx != ActualVF)
-        break;
-
-      LLVM_DEBUG(dbgs() << "SLP: Analyzing " << ActualVF << " operations "
-                        << "\n");
-
-      R.buildTree(Ops);
-      if (R.isTreeTinyAndNotFullyVectorizable())
-        continue;
-      R.reorderTopToBottom();
-      R.reorderBottomToTop(
-          /*IgnoreReorder=*/!isa<InsertElementInst>(Ops.front()) &&
-          !R.doesRootHaveInTreeUses());
-      R.transformNodes();
-      R.buildExternalUses();
-
-      R.computeMinimumValueSizes();
-      InstructionCost Cost = R.getTreeCost();
-      CandidateFound = true;
-      MinCost = std::min(MinCost, Cost);
-
-      LLVM_DEBUG(dbgs() << "SLP: Found cost = " << Cost
-                        << " for VF=" << ActualVF << "\n");
-      if (Cost < -SLPCostThreshold) {
-        LLVM_DEBUG(dbgs() << "SLP: Vectorizing list at cost:" << Cost << ".\n");
-        R.getORE()->emit(OptimizationRemark(SV_NAME, "VectorizedList",
-                                                    cast<Instruction>(Ops[0]))
-                                 << "SLP vectorized with cost " << ore::NV("Cost", Cost)
-                                 << " and with tree size "
-                                 << ore::NV("TreeSize", R.getTreeSize()));
-
-        R.vectorizeTree();
-        // Move to the next bundle.
-        I += VF - 1;
-        NextInst = I + 1;
-        Changed = true;
-      }
-    }
-  }
-
-  if (!Changed && CandidateFound) {
-    R.getORE()->emit([&]() {
-      return OptimizationRemarkMissed(SV_NAME, "NotBeneficial", I0)
-             << "List vectorization was possible but not beneficial with cost "
-             << ore::NV("Cost", MinCost) << " >= "
-             << ore::NV("Treshold", -SLPCostThreshold);
-    });
-  } else if (!Changed) {
-    R.getORE()->emit([&]() {
-      return OptimizationRemarkMissed(SV_NAME, "NotPossible", I0)
-             << "Cannot SLP vectorize list: vectorization was impossible"
-             << " with available vectorization factors";
-    });
-  }
-  return Changed;
-}
